  const tempoAtualStr   = typeof tempoAtualRaw   === "string" ? tempoAtualRaw.trim()   : tempoAtualRaw;

  const base = {
    Nome:               j["Nome"]               ?? null,
    Id:                 j["Id"]                 ?? null,
    Telefone:           j["Telefone"]           ?? null,
    Email:              j["Email"]              ?? null,
